        ]

        self.client = OpenAI(
            base_url="https://api.groq.com/openai/v1",
            api_key="REDACTED_GROQ_KEY",
        )

        self.exa_client = Exa(api_key=exa_api_key)
        self.yesterday = datetime.now().date() - timedelta(days=1)

    def read_feed_urls(self):
        with open(self.feed_file, 'r') as file:
            return json.load(file)

    def clean_html(self, content):
        try:
            soup = BeautifulSoup(content, 'html.parser')
            clean_text = ' '.join(soup.stripped_strings)
        except:
            clean_text = content
        return html.unescape(clean_text)

    def find_similar_content(self, url, max_results=5):
        try:
            response = self.exa_client.find_similar_and_contents(
                url,
                text=True,
                num_results=max_results
            )

            similar_articles = []
            for result in response.results:
                similar_articles.append({
                    'title': result.title,
                    'url': result.url,
                    'snippet': result.snippet if hasattr(result, 'snippet') else None,
                    'text': result.text if hasattr(result, 'text') else None
                })
            return similar_articles
        except Exception as e:
            print(f"Error finding similar content for URL '{url}': {str(e)}")
            return []

    def scrape_article_content(self, url):
        headers = {
            'User-Agent': random.choice(self.user_agents),
            'Accept': 'text/html, application/xhtml+xml, application/xml;q=0.9, image/webp, */*;q=0.8',
            'Accept-Language': 'en-US, en;q=0.5',
            'Referer': 'https://www.google.com/',
            'DNT': '1',
            'Connection': 'keep-alive',
            'Upgrade-Insecure-Requests': '1',
        }

        try:
            response = requests.get(url, headers=headers, timeout=10)
            response.raise_for_status()
            elements = partition_html(text=response.text)
            content = ' '.join([str(element) for element in elements])
            return self.clean_html(content)
        except Exception as e:
            print(f"Error scraping {url}: {str(e)}")
            return "Unable to scrape content"

    def generate_blog_post(self, article_content):
        prompt = f"""
        Based on the following article content, write a new blog post.
        The new post should be original, engaging, and informative, while capturing the key points and insights from the source material.

        Source content:
        {article_content[:4000]} 

        New blog post:
        """

        try:
            response = self.client.chat.completions.create(
                model="llama-3.1-70b-versatile",
                messages=[
                    {"role": "system", "content": "You are a professional AI and technology blogger."},
                    {"role": "user", "content": prompt}
                ],
                max_tokens=4000,
                temperature=0.5,
            )

